<?php
if (!defined('SDS_PERPUSTAKAAN_APP')) { http_response_code(403); exit('Akses langsung tidak diizinkan.'); }
$page='audit';require __DIR__.'/../partials/bootstrap.php';
if(!$perpusIsAdmin){http_response_code(403);echo '<div class="alert alert-danger">Hanya admin Perpustakaan yang dapat menjalankan audit.</div>';return;}
$message='';$error='';$auditResults=[];
if(($_SERVER['REQUEST_METHOD']??'')==='POST'){
 try{
  perpus_check_csrf();$action=(string)($_POST['action']??'run');$adminId=(int)($_SESSION['admin_id']??0);
  if($action==='run'){$auditResults=sds_perpus_run_integrity_audit($conn,$adminId);$message='Pemeriksaan integritas selesai dijalankan.';}
  elseif($action==='repair_safe'){
   $conn->begin_transaction();$changes=[];
   $conn->query("UPDATE perpus_buku_eksemplar e SET e.status='tersedia' WHERE e.status='dipinjam' AND NOT EXISTS(SELECT 1 FROM perpus_peminjaman_detail d WHERE d.eksemplar_id=e.id AND d.status='dipinjam')");$changes['eksemplar_dibuka']=$conn->affected_rows;
   $conn->query("UPDATE perpus_buku_eksemplar e SET e.status='dipinjam' WHERE EXISTS(SELECT 1 FROM perpus_peminjaman_detail d WHERE d.eksemplar_id=e.id AND d.status='dipinjam') AND e.status<>'dipinjam'");$changes['eksemplar_dikunci']=$conn->affected_rows;
   $conn->query("UPDATE perpus_peminjaman p SET p.jumlah_item=(SELECT COUNT(*) FROM perpus_peminjaman_detail d WHERE d.peminjaman_id=p.id)");$changes['jumlah_item']=$conn->affected_rows;
   $conn->query("UPDATE perpus_peminjaman p SET p.status='selesai' WHERE p.status='aktif' AND NOT EXISTS(SELECT 1 FROM perpus_peminjaman_detail d WHERE d.peminjaman_id=p.id AND d.status='dipinjam')");$changes['header_ditutup']=$conn->affected_rows;
   $conn->query("UPDATE perpus_peminjaman p SET p.status='aktif' WHERE p.status<>'aktif' AND EXISTS(SELECT 1 FROM perpus_peminjaman_detail d WHERE d.peminjaman_id=p.id AND d.status='dipinjam')");$changes['header_diaktifkan']=$conn->affected_rows;
   $conn->query("UPDATE perpus_peminjaman_detail d SET d.denda_status=CASE WHEN d.denda<=0 THEN 'lunas' WHEN COALESCE((SELECT SUM(x.nominal) FROM perpus_denda_pembayaran x WHERE x.detail_id=d.id),0)>=d.denda THEN IF(EXISTS(SELECT 1 FROM perpus_denda_pembayaran x WHERE x.detail_id=d.id AND x.jenis='pembebasan'),'dibebaskan','lunas') ELSE 'belum_lunas' END WHERE d.status<>'dipinjam'");$changes['status_denda']=$conn->affected_rows;
   $conn->commit();sds_perpus_audit_log($conn,'repair','sistem','','Perbaikan aman hasil audit dijalankan',null,$changes,$adminId);$auditResults=sds_perpus_run_integrity_audit($conn,$adminId);$message='Perbaikan aman selesai. Sistem menjalankan audit ulang.';
  }elseif($action==='cleanup'){
   $days=max(30,min(3650,(int)sds_perpus_setting_value($conn,'retensi_audit_hari','365')));$stmt=$conn->prepare('DELETE FROM perpus_audit_log WHERE created_at<DATE_SUB(NOW(),INTERVAL ? DAY)');$stmt->bind_param('i',$days);$stmt->execute();$deleted=$stmt->affected_rows;$stmt->close();$stmt=$conn->prepare('DELETE FROM perpus_audit_check WHERE checked_at<DATE_SUB(NOW(),INTERVAL ? DAY)');$stmt->bind_param('i',$days);$stmt->execute();$deletedChecks=$stmt->affected_rows;$stmt->close();sds_perpus_audit_log($conn,'cleanup','audit','','Pembersihan log audit lama',null,['log'=>$deleted,'check'=>$deletedChecks,'retensi_hari'=>$days],$adminId);$message=number_format($deleted+$deletedChecks,0,',','.').' log audit lama dibersihkan.';
  }else throw new RuntimeException('Aksi audit tidak valid.');
 }catch(Throwable $e){try{$conn->rollback();}catch(Throwable $x){}$error=$e->getMessage();}
}

$latestAt='';$r=$conn->query('SELECT MAX(checked_at) latest FROM perpus_audit_check');if($r)$latestAt=(string)($r->fetch_assoc()['latest']??'');
$checks=[];if($latestAt!==''){$stmt=$conn->prepare('SELECT * FROM perpus_audit_check WHERE checked_at=? ORDER BY FIELD(tingkat,\'kritis\',\'peringatan\',\'info\'),jumlah_temuan DESC,kode');$stmt->bind_param('s',$latestAt);$stmt->execute();$rr=$stmt->get_result();while($x=$rr->fetch_assoc()){$x['detail']=json_decode((string)$x['detail_json'],true)?:[];$checks[]=$x;}$stmt->close();}
if($auditResults){$checks=[];foreach($auditResults as $x)$checks[]=['kode'=>$x['kode'],'tingkat'=>$x['tingkat'],'judul'=>$x['judul'],'jumlah_temuan'=>$x['jumlah'],'detail'=>$x['detail'],'checked_at'=>date('Y-m-d H:i:s')];$latestAt=date('Y-m-d H:i:s');}
$checkStats=['kritis'=>0,'peringatan'=>0,'info'=>0,'temuan'=>0];foreach($checks as $c){if((int)$c['jumlah_temuan']>0)$checkStats[$c['tingkat']]++;$checkStats['temuan']+=(int)$c['jumlah_temuan'];}
$entity=trim((string)($_GET['entitas']??''));$actionFilter=trim((string)($_GET['aksi']??''));$q=trim((string)($_GET['q']??''));$from=trim((string)($_GET['from']??date('Y-m-d',strtotime('-30 days'))));$to=trim((string)($_GET['to']??date('Y-m-d')));if(!preg_match('/^\d{4}-\d{2}-\d{2}$/',$from))$from=date('Y-m-d',strtotime('-30 days'));if(!preg_match('/^\d{4}-\d{2}-\d{2}$/',$to))$to=date('Y-m-d');
$where=['DATE(created_at) BETWEEN ? AND ?'];$params=[$from,$to];$types='ss';if($entity!==''){$where[]='entitas=?';$params[]=$entity;$types.='s';}if($actionFilter!==''){$where[]='aksi=?';$params[]=$actionFilter;$types.='s';}if($q!==''){$where[]='(ringkasan LIKE ? OR entitas_id LIKE ? OR ip_address LIKE ?)';$like='%'.$q.'%';$params=array_merge($params,[$like,$like,$like]);$types.='sss';}
$stmt=$conn->prepare('SELECT * FROM perpus_audit_log WHERE '.implode(' AND ',$where).' ORDER BY id DESC LIMIT 500');$stmt->bind_param($types,...$params);$stmt->execute();$logs=[];$rr=$stmt->get_result();while($x=$rr->fetch_assoc())$logs[]=$x;$stmt->close();
$entities=[];$r=$conn->query('SELECT DISTINCT entitas FROM perpus_audit_log ORDER BY entitas');while($r&&($x=$r->fetch_assoc()))$entities[]=$x['entitas'];$actions=[];$r=$conn->query('SELECT DISTINCT aksi FROM perpus_audit_log ORDER BY aksi');while($r&&($x=$r->fetch_assoc()))$actions[]=$x['aksi'];
require __DIR__.'/../partials/master_page_style.php';
?>
<div class="sds-master-page perpus-audit"><div class="sds-hero"><div><h2>Audit & Integritas Sistem</h2><p>Memeriksa konsistensi koleksi, sirkulasi, denda, reservasi, anggota, dan kartu RFID.</p></div><div class="sds-hero-actions"><form method="post" class="d-inline"><input type="hidden" name="csrf" value="<?=perpus_h(perpus_csrf())?>"><input type="hidden" name="action" value="run"><button class="btn btn-primary"><i data-feather="activity" class="me-1"></i>Jalankan Audit</button></form><form method="post" class="d-inline" onsubmit="return confirm('Jalankan perbaikan aman dan audit ulang?')"><input type="hidden" name="csrf" value="<?=perpus_h(perpus_csrf())?>"><input type="hidden" name="action" value="repair_safe"><button class="btn btn-outline-success"><i data-feather="tool" class="me-1"></i>Perbaikan Aman</button></form></div></div><?php if($message):?><div class="alert alert-success"><?=perpus_h($message)?></div><?php endif;?><?php if($error):?><div class="alert alert-danger"><?=perpus_h($error)?></div><?php endif;?>
<div class="sds-stats"><div class="sds-stat-card"><small>Total Temuan</small><strong><?=number_format($checkStats['temuan'],0,',','.')?></strong><span><?= $latestAt?date('d/m/Y H:i',strtotime($latestAt)):'Belum pernah diaudit' ?></span></div><div class="sds-stat-card"><small>Pemeriksaan Kritis</small><strong><?=number_format($checkStats['kritis'],0,',','.')?></strong><span>Memerlukan perhatian segera</span></div><div class="sds-stat-card"><small>Peringatan</small><strong><?=number_format($checkStats['peringatan'],0,',','.')?></strong><span>Perlu ditinjau petugas</span></div><div class="sds-stat-card"><small>Informasi</small><strong><?=number_format($checkStats['info'],0,',','.')?></strong><span>Sinkronisasi dan status master</span></div></div>
<?php if($checks):?><div class="row g-3 mb-3"><?php foreach($checks as $c):?><div class="col-xl-6"><div class="card audit-check <?=perpus_h($c['tingkat'])?> h-100"><div class="card-body"><div class="d-flex justify-content-between gap-3"><div><strong><?=perpus_h($c['judul'])?></strong><div class="small text-muted"><code><?=perpus_h($c['kode'])?></code></div></div><span class="badge <?=((int)$c['jumlah_temuan'])>0?($c['tingkat']==='kritis'?'bg-danger':($c['tingkat']==='peringatan'?'bg-warning text-dark':'bg-info')):'bg-success'?>"><?=number_format((int)$c['jumlah_temuan'],0,',','.')?> temuan</span></div><?php if(!empty($c['detail'])):?><details class="mt-3"><summary class="small text-primary">Lihat contoh data</summary><pre><?=perpus_h(json_encode($c['detail'],JSON_PRETTY_PRINT|JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES))?></pre></details><?php endif;?></div></div></div><?php endforeach;?></div><?php else:?><div class="alert alert-info">Belum ada hasil audit. Tekan <strong>Jalankan Audit</strong> untuk memulai pemeriksaan.</div><?php endif;?>
<div class="card no-print"><div class="card-header"><h5>Filter Log Aktivitas</h5><form method="post" onsubmit="return confirm('Hapus log yang melewati masa retensi?')"><input type="hidden" name="csrf" value="<?=perpus_h(perpus_csrf())?>"><input type="hidden" name="action" value="cleanup"><button class="btn btn-sm btn-outline-danger"><i data-feather="trash-2" class="me-1"></i>Bersihkan Log Lama</button></form></div><div class="card-body"><form method="get" class="audit-filter"><div><label class="form-label">Dari</label><input class="form-control form-control-sm" type="date" name="from" value="<?=perpus_h($from)?>"></div><div><label class="form-label">Sampai</label><input class="form-control form-control-sm" type="date" name="to" value="<?=perpus_h($to)?>"></div><div><label class="form-label">Entitas</label><select class="form-select form-select-sm" name="entitas"><option value="">Semua</option><?php foreach($entities as $v):?><option value="<?=perpus_h($v)?>" <?=$entity===$v?'selected':''?>><?=perpus_h($v)?></option><?php endforeach;?></select></div><div><label class="form-label">Aksi</label><select class="form-select form-select-sm" name="aksi"><option value="">Semua</option><?php foreach($actions as $v):?><option value="<?=perpus_h($v)?>" <?=$actionFilter===$v?'selected':''?>><?=perpus_h($v)?></option><?php endforeach;?></select></div><div><label class="form-label">Pencarian</label><input class="form-control form-control-sm" name="q" value="<?=perpus_h($q)?>" placeholder="Ringkasan, ID, IP..."></div><button class="btn btn-sm btn-primary">Tampilkan</button><a class="btn btn-sm btn-outline-secondary" href="audit">Reset</a></form></div></div>
<div class="card card-outline card-secondary"><div class="card-header"><h5>Log Aktivitas</h5><span class="small text-muted">Maksimal 500 data</span></div><div class="table-responsive"><table class="table table-hover align-middle mb-0"><thead><tr><th>Waktu</th><th>Admin</th><th>Aksi</th><th>Entitas</th><th>Ringkasan</th><th>IP</th><th>Detail</th></tr></thead><tbody><?php if(!$logs):?><tr><td colspan="7" class="text-center text-muted py-4">Belum ada log pada filter ini.</td></tr><?php endif;?><?php foreach($logs as $l):?><tr><td><?=date('d/m/Y H:i:s',strtotime($l['created_at']))?></td><td><?= $l['admin_id']?('#'.(int)$l['admin_id']):'Sistem/Publik' ?></td><td><span class="badge bg-secondary"><?=perpus_h($l['aksi'])?></span></td><td><strong><?=perpus_h($l['entitas'])?></strong><div class="small text-muted"><?=perpus_h($l['entitas_id']?:'-')?></div></td><td><?=perpus_h($l['ringkasan']?:'-')?></td><td><code><?=perpus_h($l['ip_address']?:'-')?></code></td><td><?php if($l['data_lama']||$l['data_baru']):?><details><summary class="small text-primary">Lihat</summary><pre><?=perpus_h("SEBELUM:\n".($l['data_lama']?:'-')."\n\nSESUDAH:\n".($l['data_baru']?:'-'))?></pre></details><?php else:?>-<?php endif;?></td></tr><?php endforeach;?></tbody></table></div></div></div>
